import{_ as r,o as t,c as n,j as a,a as o,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"黎明之刃","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/黎明之刃.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/黎明之刃.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/黎明之刃.md"};function d(i,e,l,_,c,h){return t(),n("div",null,[...e[0]||(e[0]=[a("h1",{id:"黎明之刃",tabindex:"-1"},[o("黎明之刃 "),a("a",{class:"header-anchor",href:"#黎明之刃","aria-label":'Permalink to "黎明之刃"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="黎明之刃-1" tabindex="-1">黎明之刃 <a class="header-anchor" href="#黎明之刃-1" aria-label="Permalink to &quot;黎明之刃&quot;">​</a></h1><p>黎明之刃<br> D+1500<br> 科技本质<br> 黎明之刃是一柄用Chronophagic（希腊语，意为“吞噬时间”）合金制成的鬼头大刀，作为钛帝国唯一昭和猛男【远见.阿兹纳布尔】的爱刀， 每当远见用它杀生时,他的寿命就会被大大滴被延长，因为这柄妖刀会将死者的生命力转移给其持有者，这也使得远见在经历漫长的时间后，依然能作为赤い彗星 活跃在战场上。<br> 黎明之刃是远见在追击兽人的过程中，不小心误入某个信仰中东萨满的化外小国的领土范围内找到的，并依靠这把武器击退了一群“凭空出现的怪异生物 。不过讲真，考虑到黎明之刃的制造年代和能伤害恶魔的实际效果，塔拉辛最好检查一下自己博物馆里是不是丢了点什么东西....</p><p>黎明之刃是一把武器伤害7L，体积6的鬼头大刀，专业为【刀】、造成【挥砍】伤害，具有【锋利】【噬时】和【汲能】特性</p><p>锋利<br> 这把一人多高的武器是如此锋利，可以轻易切开岩石， 黎明之刃具有2点破甲。</p><p>噬时<br> 这把古老的利刃隐藏着一个黑暗的秘密。其刀身是由(chronophagic)合金组成的——每当使用者杀死一条鲜活的生命时，受害者原本所剩的寿命便被偷走并叠加到了使用者本人身上，这使得远见持续的活了将近三个世纪。<br> 每当人物使用该武器杀死一名生物后，便获得该生物剩余的自然寿命，每部影片中你至多从此特性获得5年自然寿命。在战斗中，人物只要使用黎明之刃杀死任意一名生物后，还可立即获得B级的【免疫衰老】效果，该效果持续一个场景。</p><p>汲能<br> 黎明之刃可以真正的伤害那些来自亚空间的怪异存在，伤害并汲取他们的能量，远见甚至凭借此刀硬刚几下恐虐大魔，让钛军借此侥得喘息之机。<br> 黎明之刃具有【法破】的特性，可以有效的杀伤那些非实体的存在，且若被攻击目标存在关键属性为全部心智属性的能量池时，则每次成功的攻击，都将使得该能量池的能量流失6点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
